1	//! Clean-room reimplementation of the tamarin-prover CLI/console text surface.
2	//!
3	//! Unit D of the relicensing effort. Every observable string in this crate was
4	//! derived from black-box probing of the compiled binary (see
5	//! `workspace/BEHAVIOR.md` and `workspace/QUERIES.log`); exact output strings
6	//! (help pages, banners, error texts) are stored as observed-output fixtures and
7	//! treated as opaque compatibility content. The parsing architecture, flag-table
8	//! model, and framing assembly are original.
9	//!
10	//! Public surface:
11	//! - [`parse`] : `parse(argv) -> Result<Command, ParseError>` — the structural
12	//!   command (mode, positionals, raw flag occurrences), or ready-to-print error.
13	//! - [`parse_args`] : `parse_args(argv) -> Result<Parsed, ParseError>` — a typed,
14	//!   value-validated command line ([`Args`]) with defaults applied.
15	//! - [`render_help`] / [`render_version`] : the help pages and version banner.
16	//! - [`framing`] : the stream-aware batch frame around opaque theory payloads.
17	//! - [`emit`] : an incremental ([`Sink`]-driven) emitter producing the same
18	//!   per-stream bytes as [`framing`] while the run is still in progress.
19	//! - [`errors`] : renderers for the runtime error lines emitted after parsing.
20	//! - [`stream`] : the two-stream output model ([`Stream`], [`Streams`]).
21	
22	pub mod args;
23	pub mod emit;
24	pub mod errors;
25	pub mod framing;
26	pub mod help;
27	pub mod modes;
28	pub mod parse;
29	pub mod stream;
30	pub mod version;
31	
32	pub use args::{parse_args, Args, OutputModule, Parsed, PartialEval, StopOnTrace};
33	pub use emit::{drive_batch, BatchEmitter, Sink, StreamCollector};
34	pub use errors::{CliError, ParseError};
35	pub use framing::{
36	    frame_batch, frame_parse_only, frame_variants, render_summary, BatchTheory, LemmaOutcome,
37	    LemmaResult, LemmaSide, LoadedTheory, Summary, TraceKind, WarningSummary,
38	};
39	pub use help::render_help;
40	pub use modes::Mode;
41	pub use parse::{parse, Command, Options, RunSpec};
42	pub use stream::{Stream, Streams};
43	pub use version::{frame_version, render_version, VersionInfo};
