        out_cap,
        err_cap,
        "YellowTest",
        None,
        vec![
            lemma("GreenYellow", TraceKind::ExistsTrace, LemmaResult::Verified, 3),
            lemma("RedYellow", TraceKind::AllTraces, LemmaResult::Falsified, 3),
